#include<bits/stdc++.h>
using namespace std;
int f[101], n, q, m;
int main() {
	cin >> n;
	for (int i = 1; i < n; i++) {
		cin >> f[i];
	}
	cin >> q;

	while (q--) {
		cin >> m;
		int a[1001] = {}, x,ans=0;
		for (int i = 0; i < m; i++) {
			cin >> x;
			while (x) a[x]++, x = f[x];
		}
		for (int i = n; i > 0; i--) {
			if (a[i] == m) {
				ans=i;
				break;
			}
		}cout<<ans<<endl;
	}
	return 0;
}
